  "units": [
    {
      "unit_id": "U1",
      "unit_name": "Matter - Its Nature and Behaviour",
      "chapters": [
        {
          "chapter_id": "C1",
          "chapter_name": "Matter in Our Surroundings",
          "topics": [
            "Definition of matter",
            "Particulate Nature of Matter",
            "States of Matter: solid, liquid and gas and their characteristics",
            "change of state- melting (absorption of heat), freezing, evaporation (cooling by evaporation), condensation, sublimation"
          ]
        },
        {
          "chapter_id": "C2",
          "chapter_name": "Is Matter Around Us Pure",
          "topics": [
            "Elements, compounds and mixtures",
            "Heterogeneous and homogenous mixtures, colloids and suspensions",
            "Physical and chemical changes (excluding separating the components of a mixture)",
            "Pure and Impure substances"
          ]
        },
        {
          "chapter_id": "C3",
          "chapter_name": "Atoms and Molecules",
          "topics": [
            "Atoms and molecules, Law of Chemical Combination, Chemical formula of common compounds, Atomic and molecular masses"
          ]
        },
        {
          "chapter_id": "C4",
          "chapter_name": "Structure of atom",
          "topics": [
            "Sub-atomic particles: Electrons, protons and neutrons",
            "Models of atom; Valency, Atomic Number and Mass Number, Isotopes and Isobars"
          ]
        }
      ]
    },
    {
      "unit_id": "U2",
      "unit_name": "Organization in the Living World",
      "chapters": [
        {
          "chapter_id": "C5",
          "chapter_name": "Cell - Basic Unit of life",
          "topics": [
            "Cell as a basic unit of life; prokaryotic and eukaryotic cells, multicellular organisms",
            "cell membrane and cell wall, cell organelles and cell inclusions; chloroplast, mitochondria, vacuoles, endoplasmic reticulum, Golgi apparatus",
            "nucleus, chromosomes - basic structure, number"
          ]
        },
        {
          "chapter_id": "C6",
          "chapter_name": "Tissues, Organs, Organ System, Organism",
          "topics": [
            "Structure and functions of animal tissues (only four types of tissues in animals; Meristematic and Permanent tissues in plants)"
          ]
        },
        {
          "chapter_id": "C7",
          "chapter_name": "Health and Diseases",
          "topics": [
            "Health and its failure. Infectious and Non-infectious diseases, their causes and manifestation",
            "Diseases caused by microbes (Virus, Bacteria and Protozoans) and their prevention; Principles of treatment and prevention",
            "Pulse Polio programmes"
          ]
        }
      ]
    },
    {
      "unit_id": "U3",
      "unit_name": "Motion, Force and Work",
      "chapters": [
        {
          "chapter_id": "C8",
          "chapter_name": "Motion",
          "topics": [
            "Distance and displacement, velocity; uniform and non-uniform motion along a straight line; acceleration",
            "distance-time and velocity-time graphs for uniform motion and uniformly accelerated motion",
            "elementary idea of uniform circular motion"
          ]
        },
        {
          "chapter_id": "C9",
          "chapter_name": "Force and Newton's laws",
          "topics": [
            "Force and Motion, Newton's Laws of Motion, Action and Reaction forces, Inertia of a body, Inertia and mass, Momentum, Force and Acceleration"
          ]
        },
        {
          "chapter_id": "C10",
          "chapter_name": "Gravitation",
          "topics": [
            "Universal Law of Gravitation, Force of Gravitation of the earth (gravity), Acceleration due to Gravity; Mass and Weight; Free fall"
          ]
        },
        {
          "chapter_id": "C11",
          "chapter_name": "Floatation",
          "topics": [
            "Thrust and Pressure. Archimedes' Principle; Buoyancy"
          ]
        },
        {
          "chapter_id": "C12",
          "chapter_name": "Work, Energy and Power",
          "topics": [
            "Work done by a Force, Energy, power; Kinetic and Potential energy; Law of conservation of energy (excluding commercial unit of Energy)"
          ]
        },
        {
          "chapter_id": "C13",
          "chapter_name": "Sound",
          "topics": [
            "Nature of sound and its propagation in various media, speed of sound, range of hearing in humans; ultrasound; reflection of sound; echo"
          ]
        }
      ]
    },
    {
      "unit_id": "U4",
      "unit_name": "Food Production",
      "chapters": [
        {
          "chapter_id": "C14",
          "chapter_name": "Plant and animal breeding and selection for quality improvement and management; Use of fertilizersand manures; Protection from pests and diseases; Organic farming"
        }
      ]
    },
    {
      "unit_id": "U5",
      "unit_name": "Chemical Substances-Nature and Behaviour",
      "chapters": [
        {
          "chapter_id": "C15",
          "chapter_name": "Chemical Reactions and Equations",
          "topics": [
            "Chemical reactions, Chemical equation, Balanced chemical equation, types of chemical reactions: combination, decomposition, displacement, double displacement, precipitation, endothermic exothermic reactions, oxidation and reduction"
          ]
        },
        {
          "chapter_id": "C16",
          "chapter_name": "Acids, Bases and Salts",
          "topics": [
            "definitions in terms of furnishing of H+ and OH– ions, identification using indicators, chemical properties, examples and uses, neutralization, concept of pH scale (Definition relating to logarithm not required), importance of pH in everyday life; preparation and uses of Sodium Hydroxide, Bleaching powder, Baking soda, Washing soda and Plaster of Paris"
          ]
        },
        {
          "chapter_id": "C17",
          "chapter_name": "Metals and Non-metals",
          "topics": [
            "Properties of metals and non-metals; Reactivity series; Formation and properties of ionic compounds; Basic metallurgical processes; Corrosion and its prevention"
          ]
        },
        {
          "chapter_id": "C18",
          "chapter_name": "Carbon and its Compounds",
          "topics": [
            "Covalent bonds – formation and properties of covalent compounds, Versatile nature of carbon, Hydrocarbons – saturated and unsaturated Homologous series. Nomenclature of alkanes, alkenes, alkyne and carbon compounds containing functional groups (halogens, alcohol, ketones, aldehydes). Chemical properties of carbon compounds (combustion, oxidation, addition and substitution reaction). Ethanol and Ethanoic acid (only properties and uses), soaps and detergents"
          ]
        }
      ]
    },
    {
      "unit_id": "U6",
      "unit_name": "World of Living",
      "chapters": [
        {
          "chapter_id": "C19",
          "chapter_name": "Life processes",
          "topics": [
            "'Living Being'. Basic concept of nutrition, respiration, transport and excretion in plants and animals"
          ]
        },
        {
          "chapter_id": "C20",
          "chapter_name": "Control and co-ordination in animals and plants",
          "topics": [
            "Tropic movements in plants; Introduction of plant hormones; Control and co-ordination in animals: Nervous system; Voluntary, involuntary and reflex action; Chemical co-ordination: animal hormones"
          ]
        },
        {
          "chapter_id": "C21",
          "chapter_name": "Reproduction",
          "topics": [
            "Reproduction in animals and plants (asexual and sexual) reproductive health - need and methods of family planning. Safe sex vs HIV/AIDS. Child bearing and women's health"
          ]
        },
        {
          "chapter_id": "C22",
          "chapter_name": "Heredity and Evolution",
          "topics": [
            "Mendel's contribution- Laws for inheritance of traits: Sex determination; brief introduction"
          ]
        }
      ]
    },
    {
      "unit_id": "U7",
      "unit_name": "Natural Phenomena",
      "chapters": [
        {
          "chapter_id": "C23",
          "chapter_name": "Reflection of light by curved surfaces; Images formed by spherical mirrors, centre of curvature, principal axis, principal focus, focal length, mirror formula (Derivation not required), magnification. Refraction; Laws of refraction, refractive index.",
          "topics": [
            "Refraction of light by spherical lens; Image formed by spherical lenses; Lens formula (Derivation not required); Magnification",
            "Power of a lens. Functioning of a lens in human eye, defects of vision and their corrections, applications of spherical mirrors and lenses"
          ]
        },
        {
          "chapter_id": "C24",
          "chapter_name": "Refraction of light through a prism, dispersion of light, scattering of light, applications in daily life (excluding colour of the sun at sunrise and sunset)",
          "topics": []
        }
      ]
    },
    {
      "unit_id": "U8",
      "unit_name": "Effects of Current",
      "chapters": [
        {
          "chapter_id": "C25",
          "chapter_name": "Electric current, potential difference and electric current. Ohm's law; Resistance, Resistivity, Factors on which the resistance of a conductor depends.",
          "topics": []
        },
        {
          "chapter_id": "C26",
          "chapter_name": "Series combination of resistors, parallel combination of resistors and its applications in daily life. Heating effect of electric current and its applications in daily life. Electric power, Interrelation between P, V, I and R.",
          "topics": []
        },
        {
          "chapter_id": "C27",
          "chapter_name": "Magnetic effects of current: Magnetic field, field lines, field due to a current carrying conductor, field due to current carrying coil or solenoid; Force on current carrying conductor, Fleming's Left Hand Rule, Direct current. Alternating current: frequency of AC. Advantage of AC over DC.",
          "topics": []
        },
        {
          "chapter_id": "C28",
          "chapter_name": "Domestic electric circuits",
          "topics": []
        }
      ]
    },
    {
      "unit_id": "U9",
      "unit_name": "Natural Resources",
      "chapters": [
        {
          "chapter_id": "C29",
          "chapter_name": "Our environment: Eco-system, Environmental problems, Ozone depletion, waste production and their solutions. Biodegradable and non-biodegradable substances.",
          "topics": []
        }
      ]
    }
  ]
